messages.content:
Para criar um OCI DevOps Project com pipeline CI/CD via Terraform:

1. **Crie o DevOps Project**:
```hcl
resource "oci_devops_project" "my_project" {
  compartment_id = var.compartment_ocid
  name           = "my-devops-project"
  description    = "DevOps project for production application"
}
```

2. **Crie o Code Repository**:
```hcl
resource "oci_devops_repository" "app_repo" {
  project_id   = oci_devops_project.my_project.id
  name         = "app-repository"
  repository_type = "HOSTED"
  description  = "Main application repository"
}
```

3. **Crie o Build Pipeline**:
```hcl
resource "oci_devops_build_pipeline" "main_pipeline" {
  project_id   = oci_devops_project.my_project.id
  display_name = "main-build-pipeline"
  description  = "Build pipeline for main branch"

  build_pipeline_stages {
    build_pipeline_stage {
      build_pipeline_stage_type = "BUILD"
      display_name              = "Build Stage"
      description               = "Build and test application"
      image                     = "OL7_X86_64_STANDARD_10"
      stage_timeout_in_seconds  = 3600

      build_spec_file = "build_spec.yaml"

      build_source_collection {
        items {
          connection_type = "DEVOPS_CODE_REPOSITORY"
          repository_id   = oci_devops_repository.app_repo.id
          branch          = "main"
          name            = "source"
        }
      }

      build_spec_build_items {
        name    = "Install Dependencies"
        type    = "COMMAND"
        command = "npm ci"
      }
      build_spec_build_items {
        name    = "Run Tests"
        type    = "COMMAND"
        command = "npm test"
      }
      build_spec_build_items {
        name    = "Build Docker Image"
        type    === "COMMAND"
        command = "docker build -t ${var.region}.ocir.io/${var.namespace}/myapp:${BUILD_RUN_ID} ."
      }
    }
  }
}
```

4. **Crie o Deploy Pipeline**:
```hcl
resource "oci_devops_deploy_pipeline" "deploy_pipeline" {
  project_id   = oci_devops_project.my_project.id
  display_name = "production-deploy-pipeline"
  description  = "Deploy to production environment"

  deploy_pipeline_stages {
    deploy_pipeline_stage {
      deploy_pipeline_stage_type = "OKE_DEPLOYMENT"
      display_name               = "Deploy to OKE"
      description                = "Deploy to OKE cluster"

      oke_cluster_deploy_environment_id = oci_devops_deploy_environment.oke_env.id
      namespace                         = var.namespace
      helm_chart_values = {
        image_tag = "${var.region}.ocir.io/${var.namespace}/myapp"
      }
    }
  }
}
```

5. **Crie os Deploy Environments**:
```hcl
resource "oci_devops_deploy_environment" "oke_env" {
  project_id             = oci_devops_project.my_project.id
  display_name           = "oke-production-environment"
  deploy_environment_type = "OKE_CLUSTER"

  oke_cluster_deploy_environment {
    cluster_id  = var.oke_cluster_ocid
    namespace   = var.namespace
  }
}
```

6. **Conecte o pipeline ao repositório**:
```hcl
resource "oci_devops_trigger" "main_trigger" {
  project_id   = oci_devops_project.my_project.id
  display_name = "main-branch-trigger"
  description  = "Trigger build on main branch push"
  actions {
    type          = "INVOKE_BUILD_PIPELINE"
    build_pipeline_id = oci_devops_build_pipeline.main_pipeline.id
  }
  filter {
    trigger_source = "DEVOPS_CODE_REPOSITORY"
    events         = ["PUSH"]
    conditions {
      condition_type = "FILE_PATH"
      file_path      = "*"
      condition      = "INCLUDE"
    }
    conditions {
      condition_type = "HEAD_REF"
      head_ref       = "refs/heads/main"
      condition      = "INCLUDE"
    }
  }
}
```

Ref: https://docs.oracle.com/en-us/iaas/Content/devops/overview.htm

Para criar e gerenciar stacks do Resource Manager via Terraform e OCI DevOps:

1. **Crie a stack do Resource Manager**:
```hcl
resource "oci_resource_manager_stack" "infra_stack" {
  compartment_id = var.compartment_ocid
  display_name   = "production-infra-stack"
  description    = "Production infrastructure stack"

  config_source {
    config_source_type = "ZIP_UPLOAD"
    zip_file_base64    = filebase64("${path.module}/infrastructure.zip")
  }

  terraform_version = "1.5.0"

  variables = {
    region            = var.region
  compartment_ocid    = var.compartment_ocid
    vcn_cidr          = "10.0.0.0/16"
    instance_count    = "3"
  }

  freeform_tags = {
    "environment" = "production"
    "managed-by"  = "resource-manager"
  }
}
```

2. **Crie um job de plan**:
```hcl
resource "oci_resource_manager_job" "plan_job" {
  stack_id   = oci_resource_manager_stack.infra_stack.id
  display_name = "plan-job"
  operation  = "PLAN"

  execution_plan_strategy = "AUTO_APPROVED"
}
```

3. **Crie um job de apply**:
```hcl
resource "oci_resource_manager_job" "apply_job" {
  stack_id   = oci_resource_manager_stack.infra_stack.id
  display_name = "apply-job"
  operation  = "APPLY"

  execution_plan_strategy = "AUTO_APPROVED"
}
```

4. **Integração com DevOps Deploy Pipeline**:
```hcl
resource "oci_devops_deploy_environment" "rm_environment" {
  project_id             = oci_devops_project.my_project.id
  display_name           = "resource-manager-environment"
  deploy_environment_type = "RESOURCE_MANAGER_STACK"

  resource_manager_stack_deploy_environment {
    stack_id = oci_resource_manager_stack.infra_stack.id
  }
}

resource "oci_devops_deploy_pipeline" "rm_deploy_pipeline" {
  project_id   = oci_devops_project.my_project.id
  display_name = "rm-deploy-pipeline"

  deploy_pipeline_stages {
    deploy_pipeline_stage {
      deploy_pipeline_stage_type = "RESOURCE_MANAGER_DEPLOY"
      display_name               = "Apply Infrastructure"

      resource_manager_stack_deploy_stage {
        action              = "APPLY"
        environment_id      = oci_devops_deploy_environment.rm_environment.id
        execution_plan_strategy = "AUTO_APPROVED"
      }
    }
  }
}
```

5. **Para usar Git como config source**:
```hcl
resource "oci_resource_manager_stack" "git_stack" {
  compartment_id = var.compartment_ocid
  display_name   = "git-backed-stack"

  config_source {
    config_source_type     = "GIT_CONFIG_SOURCE"
    repository_url         = "https://github.com/org/infra.git"
    branch                 = "main"
    working_directory      = "environments/production"
  }

  terraform_version = "1.5.0"
}
```

6. **Comparação multi-cloud**:
- Resource Manager ≈ AWS CloudFormation
- Resource Manager ≈ Azure Resource Manager (ARM) Templates
- Resource Manager ≈ GCP Deployment Manager

Ref: https://docs.oracle.com/en-us/iaas/Content/ResourceManager/home.htm

Para configurar artifacts do OCI DevOps e integrar com OCIR:

1. **Crie o Artifact (referência a imagem no OCIR)**:
```hcl
resource "oci_devops_deploy_artifact" "app_image" {
  project_id               = oci_devops_project.my_project.id
  display_name             = "app-docker-image"
  description              = "Application Docker image from OCIR"
  deploy_artifact_type     = "DOCKER_IMAGE"

  docker_image_deploy_artifact {
    image_uri  = "${var.region}.ocir.io/${var.namespace}/myapp:latest"
    repository_url = "${var.region}.ocir.io/${var.namespace}/myapp"
  }
}
```

2. **Crie o Artifact para Helm Chart**:
```hcl
resource "oci_devops_deploy_artifact" "helm_chart" {
  project_id               = oci_devops_project.my_project.id
  display_name             = "app-helm-chart"
  description              = "Helm chart for application deployment"
  deploy_artifact_type     = "HELM_CHART"

  helm_chart_deploy_artifact {
    chart_url  = "oci://${var.region}.ocir.io/${var.namespace}/helm-charts/myapp"
    version    = "1.0.0"
  }
}
```

3. **Crie o Artifact para manifest YAML**:
```hcl
resource "oci_devops_deploy_artifact" "k8s_manifest" {
  project_id               = oci_devops_project.my_project.id
  display_name             = "k8s-manifest"
  description              = "Kubernetes deployment manifest"
  deploy_artifact_type     = "MANAGED_DEPLOYMENT_SPEC"

  kubernetes_manifest_deploy_artifact {
    content = file("${path.module}/deployment.yaml")
  }
}
```

4. **Referencie os artifacts no Deploy Pipeline**:
```hcl
resource "oci_devops_deploy_pipeline" "deploy_pipeline" {
  project_id   = oci_devops_project.my_project.id
  display_name = "deploy-pipeline"

  deploy_pipeline_stages {
    deploy_pipeline_stage {
      deploy_pipeline_stage_type = "OKE_DEPLOYMENT"
      display_name               = "Deploy to OKE"

      oke_cluster_deploy_environment_id = oci_devops_deploy_environment.oke_env.id

      artifacts {
        deploy_artifact_id = oci_devops_deploy_artifact.app_image.id
        display_name       = "app-image-ref"
        artifact_override_items {
          type          = "IMAGE_AND_TAG"
          deploy_artifact_id = oci_devops_deploy_artifact.app_image.id
          value         = "${var.region}.ocir.io/${var.namespace}/myapp"
        }
      }
    }
  }
}
```

5. **Configure o OCIR**:
```hcl
# OCIR é um serviço gerenciado - não precisa de Terraform
# Mas precisa de auth token para push/pull:

# Crie o auth token via OCI CLI:
# oci iam auth-token create --description "OCIR push token"

# Ou via Terraform:
resource "oci_identity_auth_token" "ocir_token" {
  description = "OCIR push token for DevOps"
  user_id     = var.devops_user_ocid
}
```

6. **Policies para acesso ao OCIR**:
```hcl
resource "oci_identity_policy" "ocir_access_policy" {
  compartment_id = var.tenancy_ocid
  name           = "ocir-devops-policy"
  statements = [
    "Allow dynamic-group ${oci_identity_dynamic_group.build_dg.name} to manage repos in tenancy",
    "Allow dynamic-group ${oci_identity_dynamic_group.build_dg.name} to manage objects in compartment ${var.compartment_name}",
  ]
}
```

7. **Comparação multi-cloud**:
- OCIR ≈ AWS ECR (Elastic Container Registry)
- OCIR ≈ Azure Container Registry (ACR)
- OCIR ≈ GCP Artifact Registry

Ref: https://docs.oracle.com/en-us/iaas/Content/devops/using/artifacts.htm

Para configurar triggers automáticos no OCI DevOps:

1. **Crie o Trigger para push na branch main**:
```hcl
resource "oci_devops_trigger" "main_branch_trigger" {
  project_id   = oci_devops_project.my_project.id
  display_name = "main-branch-trigger"
  description  = "Trigger build on push to main branch"

  actions {
    type              = "INVOKE_BUILD_PIPELINE"
    build_pipeline_id = oci_devops_build_pipeline.main_pipeline.id
  }

  filter {
    trigger_source = "DEVOPS_CODE_REPOSITORY"
    events         = ["PUSH"]

    conditions {
      condition_type = "HEAD_REF"
      head_ref       = "refs/heads/main"
      condition      = "INCLUDE"
    }

    conditions {
      condition_type = "FILE_PATH"
      file_path      = "src/**"
      condition      = "INCLUDE"
    }

    conditions {
      condition_type = "FILE_PATH"
      file_path      = "*.md"
      condition      = "EXCLUDE"
    }
  }
}
```

2. **Trigger para pull requests**:
```hcl
resource "oci_devops_trigger" "pr_trigger" {
  project_id   = oci_devops_project.my_project.id
  display_name = "pr-validation-trigger"
  description  = "Trigger build on pull request"

  actions {
    type              = "INVOKE_BUILD_PIPELINE"
    build_pipeline_id = oci_devops_build_pipeline.pr_pipeline.id
  }

  filter {
    trigger_source = "DEVOPS_CODE_REPOSITORY"
    events         = ["PULL_REQUEST_CREATED", "PULL_REQUEST_UPDATED"]

    conditions {
      condition_type = "HEAD_REF"
      head_ref       = "refs/heads/feature/**"
      condition      = "INCLUDE"
    }
  }
}
```

3. **Trigger para tags (release)**:
```hcl
resource "oci_devops_trigger" "release_trigger" {
  project_id   = oci_devops_project.my_project.id
  display_name = "release-trigger"
  description  = "Trigger build on version tags"

  actions {
    type              = "INVOKE_BUILD_PIPELINE"
    build_pipeline_id = oci_devops_build_pipeline.release_pipeline.id
  }

  filter {
    trigger_source = "DEVOPS_CODE_REPOSITORY"
    events         = ["PUSH"]

    conditions {
      condition_type = "HEAD_REF"
      head_ref       = "refs/tags/v*"
      condition      = "INCLUDE"
    }
  }
}
```

4. **Tipos de eventos suportados**:
- `PUSH`: Push de commits
- `PULL_REQUEST_CREATED`: PR criado
- `PULL_REQUEST_UPDATED`: PR atualizado
- `PULL_REQUEST_MERGED`: PR merged

5. **Condições de filtro**:
- `HEAD_REF`: Filtra por branch/tag
- `FILE_PATH`: Filtra por caminho de arquivo
- `INCLUDE`/`EXCLUDE`: Incluir ou excluir do trigger

6. **Comparação multi-cloud**:
- OCI DevOps Triggers ≈ GitHub Actions `on: push`
- OCI DevOps Triggers ≈ AWS CodePipeline webhook
- OCI DevOps Triggers ≈ Azure DevOps pipeline triggers

Ref: https://docs.oracle.com/en-us/iaas/Content/devops/using/triggers.htm

Para configurar múltiplos environments de deploy no OCI DevOps:

1. **Crie os Deploy Environments para cada estágio**:
```hcl
# Development
resource "oci_devops_deploy_environment" "dev_env" {
  project_id             = oci_devops_project.my_project.id
  display_name           = "dev-environment"
  deploy_environment_type = "OKE_CLUSTER"

  oke_cluster_deploy_environment {
    cluster_id = var.oke_dev_cluster_ocid
    namespace  = var.namespace
  }
}

# Staging
resource "oci_devops_deploy_pipeline_stage" "staging_env" {
  project_id             = oci_devops_project.my_project.id
  display_name           = "staging-environment"
  deploy_environment_type = "OKE_CLUSTER"

  oke_cluster_deploy_environment {
    cluster_id = var.oke_staging_cluster_ocid
    namespace  = var.namespace
  }
}

# Production
resource "oci_devops_deploy_environment" "prod_env" {
  project_id             = oci_devops_project.my_project.id
  display_name           = "prod-environment"
  deploy_environment_type = "OKE_CLUSTER"

  oke_cluster_deploy_environment {
    cluster_id = var.oke_prod_cluster_ocid
    namespace  = var.namespace
  }
}
```

2. **Crie o Deploy Pipeline com aprovações**:
```hcl
resource "oci_devops_deploy_pipeline" "multi_env_pipeline" {
  project_id   = oci_devops_project.my_project.id
  display_name = "multi-env-deploy-pipeline"

  deploy_pipeline_stages {
    deploy_pipeline_stage {
      deploy_pipeline_stage_type = "OKE_DEPLOYMENT"
      display_name               = "Deploy to Dev"
      environment_id             = oci_devops_deploy_environment.dev_env.id
    }
  }

  deploy_pipeline_stages {
    deploy_pipeline_stage {
      deploy_pipeline_stage_type = "APPROVAL"
      display_name               = "Approve Staging"
      description                = "Manual approval before staging"
    }
  }

  deploy_pipeline_stages {
    deploy_pipeline_stage {
      deploy_pipeline_stage_type = "OKE_DEPLOYMENT"
      display_name               = "Deploy to Staging"
      environment_id             = oci_devops_deploy_environment.staging_env.id
    }
  }

  deploy_pipeline_stages {
    deploy_pipeline_stage {
      deploy_pipeline_stage_type = "APPROVAL"
      display_name               = "Approve Production"
      description                = "Manual approval before production"
    }
  }

  deploy_pipeline_stages {
    deploy_pipeline_stage {
      deploy_pipeline_stage_type = "OKE_DEPLOYMENT"
      display_name               = "Deploy to Production"
      environment_id             = oci_devops_deploy_environment.prod_env.id
    }
  }
}
```

3. **Crie variáveis por environment**:
```hcl
resource "oci_devops_deploy_environment" "dev_env_with_vars" {
  project_id             = oci_devops_project.my_project.id
  display_name           = "dev-environment"
  deploy_environment_type = "OKE_CLUSTER"

  oke_cluster_deploy_environment {
    cluster_id = var.oke_dev_cluster_ocid
    namespace  = var.namespace
  }

  deploy_environment_arguments {
    items {
      name         = "replica_count"
      description  = "Number of replicas"
      default_value = "1"
    }
    items {
      name         = "resource_requests_cpu"
      description  = "CPU request"
      default_value = "100m"
    }
  }
}
```

4. **Blue-Green deployment com OKE**:
```hcl
resource "oci_devops_deploy_pipeline_stage" "blue_green_deploy" {
  deploy_pipeline_stage_type = "OKE_DEPLOYMENT"
  display_name               = "Blue-Green Deploy"

  oke_cluster_deploy_environment_id = oci_devops_deploy_environment.prod_env.id

  oke_deploy_artifact {
    deploy_artifact_id = oci_devops_deploy_artifact.app_image.id
    display_name       = "app-image"
  }

  helm_deploy_artifact {
    deploy_artifact_id = oci_devops_deploy_artifact.helm_chart.id
    display_name       = "helm-chart"
  }
}
```

5. **Comparação multi-cloud**:
- OCI DevOps Environments ≈ GitHub Environments
- OCI DevOps Environments ≈ AWS CodePipeline stages
- OCI DevOps Environments ≈ Azure DevOps stages

Ref: https://docs.oracle.com/en-us/iaas/Content/devops/using/deploy_environments.htm

Para conectar um repositório GitHub externo ao OCI DevOps via Terraform:

1. **Crie a Connection com GitHub**:
```hcl
resource "oci_devops_connection" "github_connection" {
  project_id      = oci_devops_project.my_project.id
  name            = "github-connection"
  connection_type = "GITHUB"

  git_hub_access_token_connection_config {
    access_token = var.github_pat  # Personal Access Token
  }
}
```

2. **Crie a Connection com GitLab**:
```hcl
resource "oci_devops_connection" "gitlab_connection" {
  project_id      = oci_devops_project.my_project.id
  name            = "gitlab-connection"
  connection_type = "GITLAB"

  git_lab_access_token_connection_config {
    access_token = var.gitlab_pat
  }
}
```

3. **Crie a Connection com Bitbucket**:
```hcl
resource "oci_devops_connection" "bitbucket_connection" {
  project_id      = oci_devops_project.my_project.id
  name            = "bitbucket-connection"
  connection_type = "BITBUCKET_CLOUD"

  bitbucket_cloud_access_token_connection_config {
    access_token = var.bitbucket_pat
  }
}
```

4. **Use a connection no Build Pipeline**:
```hcl
resource "oci_devops_build_pipeline" "external_repo_pipeline" {
  project_id   = oci_devops_project.my_project.id
  display_name = "external-repo-pipeline"

  build_pipeline_stages {
    build_pipeline_stage {
      build_pipeline_stage_type = "BUILD"
      display_name              = "Build from GitHub"
      image                     = "OL7_X86_64_STANDARD_10"
      stage_timeout_in_seconds  = 3600
      build_spec_file           = "build_spec.yaml"

      build_source_collection {
        items {
          connection_type = "GITHUB"
          connection_id   = oci_devops_connection.github_connection.id
          repository_url  = "https://github.com/org/myapp.git"
          branch          = "main"
          name            = "source"
        }
      }
    }
  }
}
```

5. **Armazene o PAT como secret**:
```hcl
resource "oci_vault_secret" "github_pat" {
  compartment_id = var.compartment_ocid
  display_name   = "github-pat"
  vault_id       = oci_kms_vault.devops_vault.id
  key_id         = oci_kms_key.devops_key.id

  secret_content {
    content_type = "BASE64"
    content      = base64encode(var.github_pat)
  }
}
```

6. **Tipos de connection suportados**:
- `GITHUB`: GitHub.com ou GitHub Enterprise
- `GITLAB`: GitLab.com ou self-hosted
- `BITBUCKET_CLOUD`: Bitbucket Cloud
- `DEVOPS_CODE_REPOSITORY`: OCI DevOps Code Repository (hosted)

7. **Recomendações de segurança**:
- Nunca hardcode PATs no Terraform
- Use variáveis `sensitive = true`
- Armazene PATs no OCI Vault
- Rotação periódica dos tokens

Ref: https://docs.oracle.com/en-us/iaas/Content/devops/using/connections.htm
